  Example:
  const PolynomialRegression = require('ml-regression-polynomial');
  const x = [0,1,2,3], y = [1,3,5,4];
  const reg = new PolynomialRegression(x, y, 2);
  const yPred = reg.predict(2.5);

- scikitjs (npm: scikitjs): Use PolynomialFeatures + LinearRegression to create a polynomial model.
  Outline:
  const { PolynomialFeatures, LinearRegression } = require('scikitjs');
  // transform X with PolynomialFeatures(degree), then fit LinearRegression.

